#include <bits/stdc++.h>
using namespace std;
int l,r;
long long mi[15];
priority_queue<long long> pq;
bool is_prime(int x){
    if(x<2)
        return 0;
    for(int i=2;i*i<=x;i++)
        if(x%i==0)
            return 0;
    return 1;
}
void dfs(int x,long long sum){
    if(sum*sum/10>r)
        return;
    if(sum){
    	long long t=sum/10,tmp=sum;
    	bool flag=true;
    	while(t){
    		tmp=tmp*10+t%10;
    		t/=10;
    		if(tmp>r){
    			flag=false;
    			break;
    		}
		}
		if(flag && tmp>=l && is_prime(tmp))
			pq.push(-tmp);
		t=sum,tmp=sum;
    	flag=true;
    	while(t){
    		tmp=tmp*10+t%10;
    		t/=10;
    		if(tmp>r){
    			flag=false;
    			break;
    		}
		}
		if(flag && tmp>=l && is_prime(tmp))
			pq.push(-tmp);
	}
    for(int i=(x==1);i<=9;i++,i+=(x==1))
        dfs(x+1,sum*10+i);
}
int main(){
    mi[0]=1;
    for(int i=1;i<15;i++)
        mi[i]=mi[i-1]*10;
    scanf("%d%d",&l,&r);
    dfs(1,0);
    while(pq.size()){
    	printf("%lld\n",-pq.top());
    	pq.pop();
	}
    return 0;
}
